Author: "Vikas Singh"
Description: "NTFS Volume Bitmap Scan – Full volume bitmap read and validation"
EventId: 9
Channel: "Microsoft-Windows-Ntfs/Operational"
Provider: "Microsoft-Windows-Ntfs"

Maps:
  -
    Property: PayloadData1
    PropertyValue: "DevicePath: %DeviceName%"
    Values:
      -
        Name: DeviceName
        Value: "/Event/EventData/Data[@Name=\"DeviceName\"]"
  -
    Property: PayloadData2
    PropertyValue: "CorrelationId: %VolumeCorrelationId%"
    Values:
      -
        Name: VolumeCorrelationId
        Value: "/Event/EventData/Data[@Name=\"VolumeCorrelationId\"]"
  -
    Property: PayloadData3
    PropertyValue: "ReasonCode: %Reason%"
    Values:
      -
        Name: Reason
        Value: "/Event/EventData/Data[@Name=\"Reason\"]"

